  1→//! Initial h2c Request Parsing
  2→//!
  3→//! Parses the client connection preface plus the first HEADERS frame block so
  4→//! Serval can select an upstream before switching into raw h2c tunneling.
  5→
  6→const std = @import("std");
  7→const assert = std.debug.assert;
  8→
  9→const core = @import("serval-core");
 10→const config = core.config;
 11→const types = core.types;
 12→const HeaderMap = types.HeaderMap;
 13→const Method = types.Method;
 14→const Request = types.Request;
 15→
 16→const frame = @import("frame.zig");
 17→const settings = @import("settings.zig");
 18→const hpack = @import("hpack.zig");
 19→const preface = @import("preface.zig");
 20→
 21→pub const RequestHead = struct {
 22→    request: Request,
 23→    stream_id: u32,
 24→};
 25→
 26→pub const InitialRequest = struct {
 27→    request: Request,
 28→    stream_id: u32,
 29→    consumed_bytes: u32,
 30→};
 31→
 32→const priority_field_size_bytes: usize = 5;
 33→
 34→pub const Error = error{
 35→    NeedMoreData,
 36→    InvalidPreface,
 37→    InvalidFrame,
 38→    InvalidStreamId,
 39→    HeadersTooLarge,
 40→    UnsupportedContinuation,
 41→    UnsupportedPadding,
 42→    UnsupportedPriority,
 43→    MissingMethod,
 44→    MissingPath,
 45→    MissingScheme,
 46→    MissingAuthority,
 47→    InvalidMethod,
 48→    InvalidTe,
 49→    InvalidHeaderName,
 50→    UnexpectedPseudoHeader,
 51→    PseudoHeaderAfterRegularHeader,
 52→    DuplicatePseudoHeader,
 53→    ConnectionSpecificHeader,
 54→    ConnectPathNotAllowed,
 55→    ConnectSchemeNotAllowed,
 56→    AuthorityHostMismatch,
 57→    TooManyFrames,
 58→    TooManyHeaders,
 59→    DuplicateContentLength,
 60→} || frame.Error || settings.Error || hpack.Error;
 61→
 62→pub fn parseInitialRequest(input: []const u8) Error!InitialRequest {
 63→    assert(input.len > 0);
 64→
 65→    if (!preface.looksLikeClientConnectionPrefacePrefix(input)) return error.InvalidPreface;
 66→    if (input.len < preface.client_connection_preface.len) return error.NeedMoreData;
 67→
 68→    var cursor: usize = preface.client_connection_preface.len;
 69→    var frames_seen: u32 = 0;
 70→
 71→    var assembling_header_block = false;
 72→    var header_stream_id: u32 = 0;
 73→    var continuation_frames: u8 = 0;
 74→    var header_block_len: usize = 0;
 75→    var header_block_buf: [config.H2_MAX_HEADER_BLOCK_SIZE_BYTES]u8 = undefined;
 76→
 77→    while (cursor < input.len and frames_seen < config.H2_MAX_INITIAL_PARSE_FRAMES) : (frames_seen += 1) {
 78→        if (cursor + frame.frame_header_size_bytes > input.len) return error.NeedMoreData;
 79→
 80→        const header = try frame.parseFrameHeader(input[cursor..]);
 81→        const payload_start = cursor + frame.frame_header_size_bytes;
 82→        const payload_end = payload_start + header.length;
 83→        if (payload_end > input.len) return error.NeedMoreData;
 84→        const payload = input[payload_start..payload_end];
 85→
 86→        if (assembling_header_block and header.frame_type != .continuation) {
 87→            return error.InvalidFrame;
 88→        }
 89→
 90→        switch (header.frame_type) {
 91→            .settings => {
 92→                settings.validateFrame(header, payload) catch |err| switch (err) {
 93→                    error.InvalidStreamId,
 94→                    error.InvalidPayloadLength,
 95→                    error.AckMustBeEmpty,
 96→                    error.TooManySettings,
 97→                    error.InvalidEnablePush,
 98→                    error.InvalidInitialWindowSize,
 99→                    error.InvalidMaxFrameSize,
100→                    => return error.InvalidFrame,
101→                    else => return err,
102→                };
103→            },
104→            .window_update => {
105→                if (header.length != 4) return error.InvalidFrame;
106→            },
107→            .ping => {
108→                if (header.stream_id != 0 or header.length != 8) return error.InvalidFrame;
109→            },
110→            .priority => {
111→                if (header.stream_id == 0) return error.InvalidStreamId;
112→                if (header.length != priority_field_size_bytes) return error.InvalidFrame;
113→            },
114→            .headers => {
115→                if (header.stream_id == 0) return error.InvalidStreamId;
116→                if ((header.flags & frame.flags_padded) != 0) return error.UnsupportedPadding;
117→
118→                var header_fragment = payload;
119→                if ((header.flags & frame.flags_priority) != 0) {
120→                    if (payload.len < priority_field_size_bytes) return error.InvalidFrame;
121→                    header_fragment = payload[priority_field_size_bytes..];
122→                }
123→
124→                if ((header.flags & frame.flags_end_headers) != 0) {
125→                    if (header_fragment.len > config.H2_MAX_HEADER_BLOCK_SIZE_BYTES) return error.HeadersTooLarge;
126→                    return try buildInitialRequest(header_fragment, header.stream_id, @intCast(payload_end));
127→                }
128→
129→                assembling_header_block = true;
130→                header_stream_id = header.stream_id;
131→                continuation_frames = 0;
132→                header_block_len = 0;
133→                try appendHeaderFragment(&header_block_buf, &header_block_len, header_fragment);
134→            },
135→            .continuation => {
136→                if (!assembling_header_block) return error.UnsupportedContinuation;
137→                if (header.stream_id != header_stream_id) return error.InvalidStreamId;
138→                if ((header.flags & ~frame.flags_end_headers) != 0) return error.InvalidFrame;
139→
140→                if (continuation_frames >= config.H2_MAX_CONTINUATION_FRAMES) return error.TooManyFrames;
141→                continuation_frames += 1;
142→                try appendHeaderFragment(&header_block_buf, &header_block_len, payload);
143→
144→                if ((header.flags & frame.flags_end_headers) != 0) {
145→                    return try buildInitialRequest(
146→                        header_block_buf[0..header_block_len],
147→                        header_stream_id,
148→                        @intCast(payload_end),
149→                    );
150→                }
151→            },
152→            else => {},
153→        }
154→
155→        cursor = payload_end;
156→    }
157→
158→    if (frames_seen >= config.H2_MAX_INITIAL_PARSE_FRAMES) return error.TooManyFrames;
159→    return error.NeedMoreData;
160→}
161→
162→fn appendHeaderFragment(
163→    buf: *[config.H2_MAX_HEADER_BLOCK_SIZE_BYTES]u8,
164→    len: *usize,
165→    fragment: []const u8,
166→) Error!void {
167→    assert(@intFromPtr(len) != 0);
168→    assert(len.* <= config.H2_MAX_HEADER_BLOCK_SIZE_BYTES);
169→
170→    if (len.* + fragment.len > config.H2_MAX_HEADER_BLOCK_SIZE_BYTES) return error.HeadersTooLarge;
171→    @memcpy(buf[len.* .. len.* + fragment.len], fragment);
172→    len.* += fragment.len;
173→}
174→
175→fn buildInitialRequest(header_block: []const u8, stream_id: u32, consumed_bytes: u32) Error!InitialRequest {
176→    assert(header_block.len <= config.H2_MAX_HEADER_BLOCK_SIZE_BYTES);
177→    assert(stream_id > 0);
178→
179→    const head = try decodeRequestHeaderBlock(header_block, stream_id);
180→    return .{
181→        .request = head.request,
182→        .stream_id = head.stream_id,
183→        .consumed_bytes = consumed_bytes,
184→    };
185→}
186→
187→pub fn decodeRequestHeaderBlock(header_block: []const u8, stream_id: u32) Error!RequestHead {
188→    var decoder = hpack.Decoder.init();
189→    return decodeRequestHeaderBlockWithDecoder(&decoder, header_block, stream_id);
190→}
191→
192→pub fn decodeRequestHeaderBlockWithDecoder(
193→    decoder: *hpack.Decoder,
194→    header_block: []const u8,
195→    stream_id: u32,
196→) Error!RequestHead {
197→    assert(@intFromPtr(decoder) != 0);
198→    assert(header_block.len <= config.H2_MAX_HEADER_BLOCK_SIZE_BYTES);
199→    assert(stream_id > 0);
200→
201→    var fields_buf: [config.MAX_HEADERS]hpack.HeaderField = undefined;
202→    const fields = try decoder.decodeHeaderBlock(header_block, &fields_buf);
203→
204→    var request = Request{
205→        .method = .GET,
206→        .path = "",
207→        .version = .@"HTTP/1.1",
208→        .headers = HeaderMap.init(),
209→        .body = null,
210→    };
211→
212→    var method_found = false;
213→    var path_found = false;
214→    var scheme_found = false;
215→    var authority_found = false;
216→    var protocol_found = false;
217→    var regular_headers_seen = false;
218→    var connect_method = false;
219→    var authority_value: []const u8 = "";
220→
221→    for (fields) |field| {
222→        if (!isHeaderNameLowercase(field.name)) return error.InvalidHeaderName;
223→
224→        if (field.name.len > 0 and field.name[0] == ':') {
225→            if (regular_headers_seen) return error.PseudoHeaderAfterRegularHeader;
226→
227→            if (std.mem.eql(u8, field.name, ":method")) {
228→                if (method_found) return error.DuplicatePseudoHeader;
229→                request.method = parseMethod(field.value) orelse return error.InvalidMethod;
230→                method_found = true;
231→                connect_method = request.method == .CONNECT;
232→            } else if (std.mem.eql(u8, field.name, ":path")) {
233→                if (path_found) return error.DuplicatePseudoHeader;
234→                request.path = field.value;
235→                path_found = true;
236→            } else if (std.mem.eql(u8, field.name, ":scheme")) {
237→                if (scheme_found) return error.DuplicatePseudoHeader;
238→                if (field.value.len == 0) return error.MissingScheme;
239→                scheme_found = true;
240→
241→                request.headers.put("x-forwarded-proto", field.value) catch |err| switch (err) {
242→                    error.TooManyHeaders => return error.TooManyHeaders,
243→                    error.DuplicateContentLength => return error.DuplicateContentLength,
244→                };
245→            } else if (std.mem.eql(u8, field.name, ":authority")) {
246→                if (authority_found) return error.DuplicatePseudoHeader;
247→                try request.headers.put("host", field.value);
248→                authority_found = true;
249→                authority_value = field.value;
250→            } else if (std.mem.eql(u8, field.name, ":protocol")) {
251→                if (protocol_found) return error.DuplicatePseudoHeader;
252→                if (!connect_method) return error.UnexpectedPseudoHeader;
253→                if (field.value.len == 0) return error.UnexpectedPseudoHeader;
254→                protocol_found = true;
255→                try request.headers.put("x-http2-protocol", field.value);
256→            } else {
257→                return error.UnexpectedPseudoHeader;
258→            }
259→            continue;
260→        }
261→
262→        regular_headers_seen = true;
263→
264→        if (isConnectionSpecificHeader(field.name)) return error.ConnectionSpecificHeader;
265→
266→        if (std.mem.eql(u8, field.name, "te") and !isTeTrailersOnly(field.value)) {
267→            return error.InvalidTe;
268→        }
269→
270→        if (authority_found and std.mem.eql(u8, field.name, "host")) {
271→            if (!std.ascii.eqlIgnoreCase(field.value, authority_value)) return error.AuthorityHostMismatch;
272→            continue;
273→        }
274→
275→        request.headers.put(field.name, field.value) catch |err| switch (err) {
276→            error.TooManyHeaders => return error.TooManyHeaders,
277→            error.DuplicateContentLength => return error.DuplicateContentLength,
278→        };
279→    }
280→
281→    if (!method_found) return error.MissingMethod;
282→    if (!authority_found and request.headers.getHost() == null) return error.MissingAuthority;
283→
284→    if (connect_method) {
285→        if (protocol_found) {
286→            if (!path_found or request.path.len == 0) return error.MissingPath;
287→            if (!scheme_found) return error.MissingScheme;
288→        } else {
289→            if (path_found) return error.ConnectPathNotAllowed;
290→            if (scheme_found) return error.ConnectSchemeNotAllowed;
291→        }
292→    } else {
293→        if (protocol_found) return error.UnexpectedPseudoHeader;
294→        if (!path_found or request.path.len == 0) return error.MissingPath;
295→        if (!scheme_found) return error.MissingScheme;
296→    }
297→
298→    return .{ .request = request, .stream_id = stream_id };
299→}
300→
301→fn parseMethod(token: []const u8) ?Method {
302→    const map = std.StaticStringMap(Method).initComptime(.{
303→        .{ "GET", .GET },
304→        .{ "HEAD", .HEAD },
305→        .{ "POST", .POST },
306→        .{ "PUT", .PUT },
307→        .{ "DELETE", .DELETE },
308→        .{ "CONNECT", .CONNECT },
309→        .{ "OPTIONS", .OPTIONS },
310→        .{ "TRACE", .TRACE },
311→        .{ "PATCH", .PATCH },
312→    });
313→    return map.get(token);
314→}
315→
316→fn isHeaderNameLowercase(name: []const u8) bool {
317→    if (name.len == 0) return false;
318→
319→    var index: usize = 0;
320→    while (index < name.len) : (index += 1) {
321→        const c = name[index];
322→        if (c >= 'A' and c <= 'Z') return false;
323→    }
324→    return true;
325→}
326→
327→fn isConnectionSpecificHeader(name: []const u8) bool {
328→    if (std.mem.eql(u8, name, "connection")) return true;
329→    if (std.mem.eql(u8, name, "proxy-connection")) return true;
330→    if (std.mem.eql(u8, name, "keep-alive")) return true;
331→    if (std.mem.eql(u8, name, "transfer-encoding")) return true;
332→    if (std.mem.eql(u8, name, "upgrade")) return true;
333→    return false;
334→}
335→
336→fn isTeTrailersOnly(value: []const u8) bool {
337→    const trimmed = std.mem.trim(u8, value, " \t");
338→    if (trimmed.len == 0) return false;
339→
340→    var tokens = std.mem.splitScalar(u8, trimmed, ',');
341→    var seen_any = false;
342→    var token_count: u8 = 0;
343→    const token_count_max: u8 = 16;
344→
345→    while (tokens.next()) |token| {
346→        if (token_count >= token_count_max) return false;
347→        token_count += 1;
348→
349→        const token_trimmed = std.mem.trim(u8, token, " \t");
350→        if (token_trimmed.len == 0) return false;
351→        if (!std.ascii.eqlIgnoreCase(token_trimmed, "trailers")) return false;
352→        seen_any = true;
353→    }
354→
355→    return seen_any;
356→}
357→
358→const TestHeaderPair = struct {
359→    name: []const u8,
360→    value: []const u8,
361→};
362→
363→fn encodeHeaderPairs(pairs: []const TestHeaderPair, out: []u8) ![]const u8 {
364→    var len: usize = 0;
365→    for (pairs) |pair| {
366→        const encoded = try hpack.encodeLiteralHeaderWithoutIndexing(out[len..], pair.name, pair.value);
367→        len += encoded.len;
368→    }
369→    return out[0..len];
370→}
371→
372→test "parseInitialRequest parses preface and first HEADERS request" {
373→    var block_buf: [256]u8 = undefined;
374→    var block_len: usize = 0;
375→
376→    const pairs = [_]struct { name: []const u8, value: []const u8 }{
377→        .{ .name = ":method", .value = "POST" },
378→        .{ .name = ":path", .value = "/grpc.health.v1.Health/Check" },
379→        .{ .name = ":scheme", .value = "http" },
380→        .{ .name = ":authority", .value = "127.0.0.1:8080" },
381→        .{ .name = "content-type", .value = "application/grpc" },
382→        .{ .name = "te", .value = "trailers" },
383→    };
384→
385→    for (pairs) |pair| {
386→        const encoded = try hpack.encodeLiteralHeaderWithoutIndexing(block_buf[block_len..], pair.name, pair.value);
387→        block_len += encoded.len;
388→    }
389→
390→    var frame_header_buf: [frame.frame_header_size_bytes]u8 = undefined;
391→    const headers_header = try frame.buildFrameHeader(&frame_header_buf, .{
392→        .length = @intCast(block_len),
393→        .frame_type = .headers,
394→        .flags = frame.flags_end_headers | frame.flags_end_stream,
395→        .stream_id = 1,
396→    });
397→
398→    var input_buf: [512]u8 = undefined;
399→    var pos: usize = 0;
400→    @memcpy(input_buf[pos..][0..preface.client_connection_preface.len], preface.client_connection_preface);
401→    pos += preface.client_connection_preface.len;
402→
403→    const settings_header = try frame.buildFrameHeader(input_buf[pos..][0..frame.frame_header_size_bytes], .{
404→        .length = 0,
405→        .frame_type = .settings,
406→        .flags = 0,
407→        .stream_id = 0,
408→    });
409→    pos += settings_header.len;
410→    @memcpy(input_buf[pos..][0..headers_header.len], headers_header);
411→    pos += headers_header.len;
412→    @memcpy(input_buf[pos..][0..block_len], block_buf[0..block_len]);
413→    pos += block_len;
414→
415→    const parsed = try parseInitialRequest(input_buf[0..pos]);
416→    try std.testing.expectEqual(Method.POST, parsed.request.method);
417→    try std.testing.expectEqualStrings("/grpc.health.v1.Health/Check", parsed.request.path);
418→    try std.testing.expectEqualStrings("application/grpc", parsed.request.headers.get("content-type").?);
419→    try std.testing.expectEqual(@as(u32, 1), parsed.stream_id);
420→}
