422→test "parseInitialRequest reassembles HEADERS and CONTINUATION" {
423→    var block_buf: [512]u8 = undefined;
424→    var block_len: usize = 0;
425→
426→    const pairs = [_]struct { name: []const u8, value: []const u8 }{
427→        .{ .name = ":method", .value = "POST" },
428→        .{ .name = ":path", .value = "/grpc.test.Echo/Continuation" },
429→        .{ .name = ":scheme", .value = "http" },
430→        .{ .name = ":authority", .value = "127.0.0.1:8080" },
431→        .{ .name = "content-type", .value = "application/grpc" },
432→        .{ .name = "te", .value = "trailers" },
433→    };
434→
435→    for (pairs) |pair| {
436→        const encoded = try hpack.encodeLiteralHeaderWithoutIndexing(block_buf[block_len..], pair.name, pair.value);
437→        block_len += encoded.len;
438→    }
439→
440→    const split: usize = block_len / 2;
441→    std.debug.assert(split > 0);
442→    std.debug.assert(split < block_len);
443→
444→    var input_buf: [1024]u8 = undefined;
445→    var pos: usize = 0;
446→
447→    @memcpy(input_buf[pos..][0..preface.client_connection_preface.len], preface.client_connection_preface);
448→    pos += preface.client_connection_preface.len;
449→
450→    const settings_header = try frame.buildFrameHeader(input_buf[pos..][0..frame.frame_header_size_bytes], .{
451→        .length = 0,
452→        .frame_type = .settings,
453→        .flags = 0,
454→        .stream_id = 0,
455→    });
456→    pos += settings_header.len;
457→
458→    const headers_header = try frame.buildFrameHeader(input_buf[pos..][0..frame.frame_header_size_bytes], .{
459→        .length = @intCast(split),
460→        .frame_type = .headers,
461→        .flags = 0,
462→        .stream_id = 1,
463→    });
464→    pos += headers_header.len;
465→    @memcpy(input_buf[pos..][0..split], block_buf[0..split]);
466→    pos += split;
467→
468→    const continuation_payload_len = block_len - split;
469→    const continuation_header = try frame.buildFrameHeader(input_buf[pos..][0..frame.frame_header_size_bytes], .{
470→        .length = @intCast(continuation_payload_len),
471→        .frame_type = .continuation,
472→        .flags = frame.flags_end_headers,
473→        .stream_id = 1,
474→    });
475→    pos += continuation_header.len;
476→    @memcpy(input_buf[pos..][0..continuation_payload_len], block_buf[split..block_len]);
477→    pos += continuation_payload_len;
478→
479→    const parsed = try parseInitialRequest(input_buf[0..pos]);
480→    try std.testing.expectEqual(Method.POST, parsed.request.method);
481→    try std.testing.expectEqualStrings("/grpc.test.Echo/Continuation", parsed.request.path);
482→    try std.testing.expectEqual(@as(u32, 1), parsed.stream_id);
483→    try std.testing.expectEqual(@as(u32, @intCast(pos)), parsed.consumed_bytes);
484→}
