486→test "parseInitialRequest accepts PRIORITY frame before request HEADERS" {
487→    var block_buf: [256]u8 = undefined;
488→    var block_len: usize = 0;
489→
490→    const pairs = [_]struct { name: []const u8, value: []const u8 }{
491→        .{ .name = ":method", .value = "POST" },
492→        .{ .name = ":path", .value = "/grpc.test.Echo/PriorityFrame" },
493→        .{ .name = ":scheme", .value = "http" },
494→        .{ .name = ":authority", .value = "127.0.0.1:8080" },
495→        .{ .name = "content-type", .value = "application/grpc" },
496→        .{ .name = "te", .value = "trailers" },
497→    };
498→
499→    for (pairs) |pair| {
500→        const encoded = try hpack.encodeLiteralHeaderWithoutIndexing(block_buf[block_len..], pair.name, pair.value);
501→        block_len += encoded.len;
502→    }
503→
504→    var input_buf: [1024]u8 = undefined;
505→    var pos: usize = 0;
506→
507→    @memcpy(input_buf[pos..][0..preface.client_connection_preface.len], preface.client_connection_preface);
508→    pos += preface.client_connection_preface.len;
509→
510→    const settings_header = try frame.buildFrameHeader(input_buf[pos..][0..frame.frame_header_size_bytes], .{
511→        .length = 0,
512→        .frame_type = .settings,
513→        .flags = 0,
514→        .stream_id = 0,
515→    });
516→    pos += settings_header.len;
517→
518→    const priority_header = try frame.buildFrameHeader(input_buf[pos..][0..frame.frame_header_size_bytes], .{
519→        .length = priority_field_size_bytes,
520→        .frame_type = .priority,
521→        .flags = 0,
522→        .stream_id = 1,
523→    });
524→    pos += priority_header.len;
525→    std.mem.writeInt(u32, input_buf[pos..][0..4], 0, .big);
526→    input_buf[pos + 4] = 15;
527→    pos += priority_field_size_bytes;
528→
529→    const headers_header = try frame.buildFrameHeader(input_buf[pos..][0..frame.frame_header_size_bytes], .{
530→        .length = @intCast(block_len),
531→        .frame_type = .headers,
532→        .flags = frame.flags_end_headers,
533→        .stream_id = 1,
534→    });
535→    pos += headers_header.len;
536→    @memcpy(input_buf[pos..][0..block_len], block_buf[0..block_len]);
537→    pos += block_len;
538→
539→    const parsed = try parseInitialRequest(input_buf[0..pos]);
540→    try std.testing.expectEqualStrings("/grpc.test.Echo/PriorityFrame", parsed.request.path);
541→    try std.testing.expectEqual(@as(u32, 1), parsed.stream_id);
542→}
