544→test "parseInitialRequest accepts HEADERS with PRIORITY flag" {
545→    var block_buf: [256]u8 = undefined;
546→    var block_len: usize = 0;
547→
548→    const pairs = [_]struct { name: []const u8, value: []const u8 }{
549→        .{ .name = ":method", .value = "POST" },
550→        .{ .name = ":path", .value = "/grpc.test.Echo/HeadersPriority" },
551→        .{ .name = ":scheme", .value = "http" },
552→        .{ .name = ":authority", .value = "127.0.0.1:8080" },
553→        .{ .name = "content-type", .value = "application/grpc" },
554→        .{ .name = "te", .value = "trailers" },
555→    };
556→
557→    for (pairs) |pair| {
