  1→//! HTTP/2 Stream State Machine Helpers
  2→//!
  3→//! Explicit bounded stream lifecycle tracking for future stream-aware HTTP/2
  4→//! transport and proxy code.
  5→//! TigerStyle: Fixed-capacity tables, explicit transitions, no allocation.
  6→
  7→const std = @import("std");
  8→const assert = std.debug.assert;
  9→const config = @import("serval-core").config;
 10→const flow = @import("flow_control.zig");
 11→
 12→const table_capacity: usize = config.H2_MAX_CONCURRENT_STREAMS;
 13→
 14→pub const Role = enum {
 15→    client,
 16→    server,
 17→};
 18→
 19→pub const State = enum {
 20→    idle,
 21→    reserved_local,
 22→    reserved_remote,
 23→    open,
 24→    half_closed_local,
 25→    half_closed_remote,
 26→    closed,
 27→};
 28→
 29→pub const Error = error{
 30→    InvalidStreamId,
 31→    WrongStreamParity,
 32→    StreamIdRegression,
 33→    StreamAlreadyExists,
 34→    StreamTableFull,
 35→    StreamNotFound,
 36→    InvalidTransition,
 37→} || flow.Error;
 38→
 39→pub const Stream = struct {
 40→    id: u32 = 0,
 41→    state: State = .idle,
 42→    recv_window: flow.Window = .{ .available_bytes = config.H2_INITIAL_WINDOW_SIZE_BYTES },
 43→    send_window: flow.Window = .{ .available_bytes = config.H2_INITIAL_WINDOW_SIZE_BYTES },
 44→
 45→    pub fn init(id: u32) Stream {
 46→        assert(isValidStreamId(id));
 47→        return .{ .id = id };
 48→    }
 49→
 50→    pub fn openLocal(self: *Stream, end_stream: bool) Error!void {
 51→        assert(self.id > 0);
 52→        if (self.state != .idle) return error.InvalidTransition;
 53→        self.state = if (end_stream) .half_closed_local else .open;
 54→    }
 55→
 56→    pub fn openRemote(self: *Stream, end_stream: bool) Error!void {
 57→        assert(self.id > 0);
 58→        if (self.state != .idle) return error.InvalidTransition;
 59→        self.state = if (end_stream) .half_closed_remote else .open;
 60→    }
 61→
 62→    pub fn reserveLocal(self: *Stream) Error!void {
 63→        assert(self.id > 0);
 64→        if (self.state != .idle) return error.InvalidTransition;
 65→        self.state = .reserved_local;
 66→    }
 67→
 68→    pub fn reserveRemote(self: *Stream) Error!void {
 69→        assert(self.id > 0);
 70→        if (self.state != .idle) return error.InvalidTransition;
 71→        self.state = .reserved_remote;
 72→    }
 73→
 74→    pub fn activateReservedLocal(self: *Stream, end_stream: bool) Error!void {
 75→        assert(self.id > 0);
 76→        if (self.state != .reserved_local) return error.InvalidTransition;
 77→        self.state = if (end_stream) .closed else .half_closed_remote;
 78→    }
 79→
 80→    pub fn activateReservedRemote(self: *Stream, end_stream: bool) Error!void {
 81→        assert(self.id > 0);
 82→        if (self.state != .reserved_remote) return error.InvalidTransition;
 83→        self.state = if (end_stream) .closed else .half_closed_local;
 84→    }
 85→
 86→    pub fn endLocal(self: *Stream) Error!void {
 87→        assert(self.id > 0);
 88→        self.state = switch (self.state) {
 89→            .open => .half_closed_local,
 90→            .half_closed_remote => .closed,
 91→            else => return error.InvalidTransition,
 92→        };
 93→    }
 94→
 95→    pub fn endRemote(self: *Stream) Error!void {
 96→        assert(self.id > 0);
 97→        self.state = switch (self.state) {
 98→            .open => .half_closed_remote,
 99→            .half_closed_local => .closed,
100→            else => return error.InvalidTransition,
101→        };
102→    }
103→
104→    pub fn reset(self: *Stream) void {
105→        assert(self.id > 0);
106→        self.state = .closed;
107→    }
108→
109→    pub fn isClosed(self: *const Stream) bool {
110→        return self.state == .closed;
111→    }
112→
113→    pub fn localCanSend(self: *const Stream) bool {
114→        return switch (self.state) {
115→            .open, .half_closed_remote => true,
116→            else => false,
117→        };
118→    }
119→
120→    pub fn remoteCanSend(self: *const Stream) bool {
121→        return switch (self.state) {
122→            .open, .half_closed_local => true,
123→            else => false,
124→        };
125→    }
126→
127→    pub fn configureWindows(self: *Stream, recv_initial_bytes: u32, send_initial_bytes: u32) Error!void {
128→        assert(self.id > 0);
129→        assert(recv_initial_bytes <= config.H2_MAX_WINDOW_SIZE_BYTES);
130→
131→        try self.recv_window.set(recv_initial_bytes);
132→        try self.send_window.set(send_initial_bytes);
133→    }
134→
135→    pub fn consumeRecvWindow(self: *Stream, bytes: u32) Error!void {
136→        assert(self.id > 0);
137→        assert(bytes <= config.H2_MAX_WINDOW_SIZE_BYTES);
138→        try self.recv_window.consume(bytes);
139→    }
140→
141→    pub fn consumeSendWindow(self: *Stream, bytes: u32) Error!void {
142→        assert(self.id > 0);
143→        assert(bytes <= config.H2_MAX_WINDOW_SIZE_BYTES);
144→        try self.send_window.consume(bytes);
145→    }
146→
