148→        assert(self.id > 0);
149→        assert(delta_bytes <= config.H2_MAX_WINDOW_SIZE_BYTES);
150→        try self.send_window.increment(delta_bytes);
151→    }
152→
153→    pub fn incrementRecvWindow(self: *Stream, delta_bytes: u32) Error!void {
