160→const Slot = struct {
161→    used: bool = false,
162→    stream: Stream = .{},
163→};
164→
165→pub const StreamTable = struct {
166→    role: Role,
167→    slots: [table_capacity]Slot = [_]Slot{.{}} ** table_capacity,
168→    active_count: u16 = 0,
169→    last_local_stream_id: u32 = 0,
170→    last_remote_stream_id: u32 = 0,
171→
172→    pub fn init(role: Role) StreamTable {
173→        return .{ .role = role };
174→    }
175→
176→    pub fn openLocal(self: *StreamTable, stream_id: u32, end_stream: bool) Error!*Stream {
177→        try validateNewStreamId(self.role, stream_id, .local, self.last_local_stream_id);
178→        if (self.findIndex(stream_id) != null) return error.StreamAlreadyExists;
179→
180→        const index = self.allocSlot() orelse return error.StreamTableFull;
181→        self.slots[index].used = true;
182→        self.slots[index].stream = Stream.init(stream_id);
183→        try self.slots[index].stream.openLocal(end_stream);
184→        self.active_count += 1;
185→        self.last_local_stream_id = stream_id;
186→        return &self.slots[index].stream;
187→    }
188→
189→    pub fn openRemote(self: *StreamTable, stream_id: u32, end_stream: bool) Error!*Stream {
190→        try validateNewStreamId(self.role, stream_id, .remote, self.last_remote_stream_id);
191→        if (self.findIndex(stream_id) != null) return error.StreamAlreadyExists;
192→
193→        const index = self.allocSlot() orelse return error.StreamTableFull;
194→        self.slots[index].used = true;
195→        self.slots[index].stream = Stream.init(stream_id);
196→        try self.slots[index].stream.openRemote(end_stream);
197→        self.active_count += 1;
198→        self.last_remote_stream_id = stream_id;
199→        return &self.slots[index].stream;
200→    }
201→
202→    pub fn get(self: *StreamTable, stream_id: u32) ?*Stream {
203→        const index = self.findIndex(stream_id) orelse return null;
204→        return &self.slots[index].stream;
205→    }
206→
207→    pub fn endLocal(self: *StreamTable, stream_id: u32) Error!void {
208→        const index = self.findIndex(stream_id) orelse return error.StreamNotFound;
209→        try self.slots[index].stream.endLocal();
210→        self.releaseIfClosed(index);
211→    }
212→
213→    pub fn endRemote(self: *StreamTable, stream_id: u32) Error!void {
214→        const index = self.findIndex(stream_id) orelse return error.StreamNotFound;
215→        try self.slots[index].stream.endRemote();
216→        self.releaseIfClosed(index);
217→    }
218→
219→    pub fn reset(self: *StreamTable, stream_id: u32) Error!void {
220→        const index = self.findIndex(stream_id) orelse return error.StreamNotFound;
221→        self.slots[index].stream.reset();
222→        self.releaseIfClosed(index);
223→    }
224→
225→    pub fn consumeRecvWindow(self: *StreamTable, stream_id: u32, bytes: u32) Error!void {
226→        const index = self.findIndex(stream_id) orelse return error.StreamNotFound;
227→        try self.slots[index].stream.consumeRecvWindow(bytes);
228→    }
229→
230→    pub fn consumeSendWindow(self: *StreamTable, stream_id: u32, bytes: u32) Error!void {
231→        const index = self.findIndex(stream_id) orelse return error.StreamNotFound;
232→        try self.slots[index].stream.consumeSendWindow(bytes);
233→    }
234→
235→    pub fn incrementSendWindow(self: *StreamTable, stream_id: u32, delta_bytes: u32) Error!void {
236→        const index = self.findIndex(stream_id) orelse return error.StreamNotFound;
237→        try self.slots[index].stream.incrementSendWindow(delta_bytes);
238→    }
239→
240→    pub fn incrementRecvWindow(self: *StreamTable, stream_id: u32, delta_bytes: u32) Error!void {
241→        const index = self.findIndex(stream_id) orelse return error.StreamNotFound;
242→        try self.slots[index].stream.incrementRecvWindow(delta_bytes);
243→    }
244→
245→    pub fn adjustAllSendWindows(self: *StreamTable, delta_bytes: i64) void {
246→        for (self.slots[0..]) |*slot| {
247→            if (!slot.used) continue;
248→
249→            if (delta_bytes >= 0) {
250→                const delta_u32: u32 = @intCast(delta_bytes);
251→                const current: u64 = slot.stream.send_window.available_bytes;
252→                const next: u64 = current + delta_u32;
253→                slot.stream.send_window.available_bytes = if (next > config.H2_MAX_WINDOW_SIZE_BYTES)
254→                    config.H2_MAX_WINDOW_SIZE_BYTES
255→                else
256→                    @intCast(next);
257→            } else {
258→                const dec_u64: u64 = @intCast(-delta_bytes);
259→                const current: u64 = slot.stream.send_window.available_bytes;
260→                if (dec_u64 >= current) {
261→                    slot.stream.send_window.available_bytes = 0;
262→                } else {
263→                    slot.stream.send_window.available_bytes = @intCast(current - dec_u64);
264→                }
265→            }
266→        }
267→    }
268→
269→    fn findIndex(self: *const StreamTable, stream_id: u32) ?usize {
270→        for (self.slots, 0..) |slot, index| {
271→            if (!slot.used) continue;
272→            if (slot.stream.id == stream_id) return index;
273→        }
274→        return null;
275→    }
276→
277→    fn allocSlot(self: *const StreamTable) ?usize {
278→        if (self.active_count >= config.H2_MAX_CONCURRENT_STREAMS) return null;
279→
280→        for (self.slots, 0..) |slot, index| {
281→            if (!slot.used) return index;
282→        }
283→        return null;
284→    }
285→
286→    fn releaseIfClosed(self: *StreamTable, index: usize) void {
287→        assert(index < self.slots.len);
288→        if (!self.slots[index].used) return;
289→        if (!self.slots[index].stream.isClosed()) return;
290→
291→        self.slots[index] = .{};
292→        assert(self.active_count > 0);
293→        self.active_count -= 1;
294→    }
295→};
296→
297→const Initiator = enum {
298→    local,
299→    remote,
300→};
301→
302→fn validateNewStreamId(role: Role, stream_id: u32, initiator: Initiator, last_stream_id: u32) Error!void {
303→    if (!isValidStreamId(stream_id)) return error.InvalidStreamId;
304→    if (stream_id <= last_stream_id) return error.StreamIdRegression;
305→    if (streamIdIsOdd(stream_id) != expectedOddParity(role, initiator)) {
306→        return error.WrongStreamParity;
307→    }
308→}
309→
310→fn isValidStreamId(stream_id: u32) bool {
311→    if (stream_id == 0) return false;
312→    return (stream_id & 0x8000_0000) == 0;
313→}
314→
315→fn streamIdIsOdd(stream_id: u32) bool {
316→    return (stream_id & 1) == 1;
317→}
318→
319→fn expectedOddParity(role: Role, initiator: Initiator) bool {
320→    return switch (role) {
321→        .client => initiator == .local,
322→        .server => initiator == .remote,
323→    };
324→}
325→
326→test "client local stream ids are odd" {
327→    var table = StreamTable.init(.client);
328→    _ = try table.openLocal(1, false);
329→    try std.testing.expectError(error.WrongStreamParity, table.openLocal(2, false));
330→}
331→
332→test "server remote stream ids are odd" {
333→    var table = StreamTable.init(.server);
334→    _ = try table.openRemote(1, false);
335→    try std.testing.expectError(error.WrongStreamParity, table.openRemote(2, false));
336→}
337→
338→test "stream transitions open to closed" {
339→    var stream = Stream.init(1);
340→    try stream.openLocal(false);
341→    try std.testing.expect(stream.localCanSend());
342→    try std.testing.expect(stream.remoteCanSend());
343→
344→    try stream.endRemote();
345→    try std.testing.expect(stream.state == .half_closed_remote);
346→    try std.testing.expect(stream.localCanSend());
347→    try std.testing.expect(!stream.remoteCanSend());
348→
349→    try stream.endLocal();
350→    try std.testing.expect(stream.isClosed());
351→}
352→
353→test "reserved stream activation transitions correctly" {
354→    var stream = Stream.init(2);
355→    try stream.reserveLocal();
356→    try stream.activateReservedLocal(false);
357→    try std.testing.expect(stream.state == .half_closed_remote);
358→}
359→
360→test "stream window helpers enforce bounded accounting" {
361→    var stream = Stream.init(1);
362→    try stream.configureWindows(32, 64);
363→    try stream.consumeRecvWindow(8);
364→    try stream.incrementRecvWindow(4);
365→    try stream.incrementSendWindow(8);
366→
367→    try std.testing.expectEqual(@as(u32, 28), stream.recv_window.available_bytes);
368→    try std.testing.expectEqual(@as(u32, 72), stream.send_window.available_bytes);
369→}
370→
371→test "stream table enforces monotonic ids" {
372→    var table = StreamTable.init(.client);
373→    _ = try table.openLocal(1, false);
374→    try std.testing.expectError(error.StreamIdRegression, table.openLocal(1, false));
375→}
376→
377→test "stream table releases closed streams" {
378→    var table = StreamTable.init(.server);
379→    _ = try table.openRemote(1, false);
380→    try table.endLocal(1);
381→    try std.testing.expectEqual(@as(u16, 1), table.active_count);
382→
383→    try table.endRemote(1);
384→    try std.testing.expectEqual(@as(u16, 0), table.active_count);
385→    try std.testing.expect(table.get(1) == null);
386→}
387→
388→test "stream table rejects capacity overflow" {
389→    var table = StreamTable.init(.client);
390→
391→    var stream_id: u32 = 1;
392→    var opened: u16 = 0;
393→    while (opened < config.H2_MAX_CONCURRENT_STREAMS) : (opened += 1) {
394→        _ = try table.openLocal(stream_id, false);
395→        stream_id += 2;
396→    }
397→
398→    try std.testing.expectError(error.StreamTableFull, table.openLocal(stream_id, false));
399→}
