  1→//! Minimal HPACK Helpers
  2→//!
  3→//! Supports a bounded safe subset sufficient for Serval's current h2c/gRPC
  4→//! parsing and client/server helpers.
  5→//!
  6→//! Supported:
  7→//! - indexed header fields from static and dynamic tables
  8→//! - literal header field with incremental indexing
  9→//! - literal header field without indexing
 10→//! - literal header field never indexed
 11→//! - indexed header names from static and dynamic tables
 12→//! - dynamic-table size updates (bounded, ordered)
 13→//! - Huffman string decoding
 14→
 15→const std = @import("std");
 16→const assert = std.debug.assert;
 17→const config = @import("serval-core").config;
 18→const huffman = @import("huffman.zig");
 19→
 20→pub const HeaderField = struct {
 21→    name: []const u8,
 22→    value: []const u8,
 23→};
 24→
 25→pub const Error = error{
 26→    NeedMoreData,
 27→    BufferTooSmall,
 28→    TooManyHeaders,
 29→    IntegerOverflow,
 30→    InvalidStringLength,
 31→    InvalidIndex,
 32→    UnsupportedDynamicTableIndex,
 33→    DynamicTableSizeTooLarge,
 34→    InvalidDynamicTableSizeUpdate,
 35→    InvalidHuffman,
 36→};
 37→
 38→const default_dynamic_table_size_bytes: u32 = 4096;
 39→const dynamic_entry_overhead_size_bytes: u32 = 32;
 40→const dynamic_storage_capacity_bytes: usize = config.H2_MAX_HEADER_BLOCK_SIZE_BYTES;
 41→const dynamic_entry_capacity: usize = 256;
 42→const huffman_scratch_capacity_bytes: usize = config.H2_MAX_HEADER_BLOCK_SIZE_BYTES * 2;
 43→
 44→const DynamicEntry = struct {
 45→    name_offset: u16,
 46→    name_len: u16,
 47→    value_offset: u16,
 48→    value_len: u16,
 49→    size_bytes: u32,
 50→};
 51→
 52→pub const Decoder = struct {
 53→    max_dynamic_table_size_bytes: u32 = default_dynamic_table_size_bytes,
 54→    dynamic_table_size_limit_bytes: u32 = default_dynamic_table_size_bytes,
 55→    current_dynamic_table_size_bytes: u32 = 0,
 56→    dynamic_entry_count: u16 = 0,
 57→    dynamic_entries: [dynamic_entry_capacity]DynamicEntry = [_]DynamicEntry{.{
 58→        .name_offset = 0,
 59→        .name_len = 0,
 60→        .value_offset = 0,
 61→        .value_len = 0,
 62→        .size_bytes = 0,
 63→    }} ** dynamic_entry_capacity,
 64→    dynamic_storage_len: u16 = 0,
 65→    dynamic_storage_buf: [dynamic_storage_capacity_bytes]u8 = undefined,
 66→    huffman_scratch_len: u16 = 0,
 67→    huffman_scratch_buf: [huffman_scratch_capacity_bytes]u8 = undefined,
 68→
 69→    pub fn init() Decoder {
 70→        return .{};
 71→    }
 72→
 73→    pub fn setMaxDynamicTableSize(self: *Decoder, max_size_bytes: u32) Error!void {
 74→        assert(@intFromPtr(self) != 0);
 75→
 76→        if (max_size_bytes > dynamic_storage_capacity_bytes) return error.DynamicTableSizeTooLarge;
 77→        self.max_dynamic_table_size_bytes = max_size_bytes;
 78→        if (self.dynamic_table_size_limit_bytes > max_size_bytes) {
 79→            self.dynamic_table_size_limit_bytes = max_size_bytes;
 80→        }
 81→
 82→        while (self.current_dynamic_table_size_bytes > self.dynamic_table_size_limit_bytes) {
 83→            evictOldestDynamicEntry(self);
 84→        }
 85→    }
 86→
 87→    pub fn decodeHeaderBlock(self: *Decoder, input: []const u8, out_fields: []HeaderField) Error![]const HeaderField {
 88→        assert(@intFromPtr(self) != 0);
 89→        assert(out_fields.len > 0);
 90→
 91→        self.huffman_scratch_len = 0;
 92→
 93→        var cursor: usize = 0;
 94→        var count: u32 = 0;
 95→        var saw_field = false;
 96→
 97→        while (cursor < input.len) {
 98→            if (count >= out_fields.len) return error.TooManyHeaders;
 99→
100→            const first = input[cursor];
101→            if ((first & 0x80) != 0) {
102→                const index = try decodeInteger(input, &cursor, 7);
103→                const field = try resolveIndexedHeader(self, index);
104→                out_fields[count] = field;
105→                count += 1;
106→                saw_field = true;
107→                continue;
108→            }
109→
110→            if ((first & 0x40) != 0) {
111→                const name = try decodeHeaderName(self, input, &cursor, 6);
112→                const value = try decodeString(self, input, &cursor);
113→                out_fields[count] = .{ .name = name, .value = value };
114→                count += 1;
115→                saw_field = true;
116→                try insertDynamicEntry(self, name, value);
117→                continue;
118→            }
119→
120→            if ((first & 0x20) != 0) {
121→                if (saw_field) return error.InvalidDynamicTableSizeUpdate;
122→                const dynamic_table_size = try decodeInteger(input, &cursor, 5);
123→                try applyDynamicTableSizeUpdate(self, dynamic_table_size);
124→                continue;
125→            }
126→
127→            const name = try decodeHeaderName(self, input, &cursor, 4);
128→            const value = try decodeString(self, input, &cursor);
129→            out_fields[count] = .{ .name = name, .value = value };
130→            count += 1;
131→            saw_field = true;
132→        }
133→
134→        return out_fields[0..count];
135→    }
136→};
137→
138→pub fn decodeHeaderBlock(input: []const u8, out_fields: []HeaderField) Error![]const HeaderField {
139→    var decoder = Decoder.init();
140→    return decoder.decodeHeaderBlock(input, out_fields);
141→}
142→
143→pub fn decodeHeaderBlockWithDecoder(
144→    decoder: *Decoder,
145→    input: []const u8,
146→    out_fields: []HeaderField,
147→) Error![]const HeaderField {
148→    assert(@intFromPtr(decoder) != 0);
149→    return decoder.decodeHeaderBlock(input, out_fields);
150→}
151→
152→pub fn encodeLiteralHeaderWithoutIndexing(
153→    out: []u8,
154→    name: []const u8,
155→    value: []const u8,
156→) Error![]const u8 {
157→    assert(name.len > 0);
158→
159→    var cursor: usize = 0;
160→    if (cursor >= out.len) return error.BufferTooSmall;
161→
162→    out[cursor] = 0x00;
163→    cursor += 1;
164→    cursor = try encodeString(out, cursor, name);
165→    cursor = try encodeString(out, cursor, value);
166→    return out[0..cursor];
167→}
168→
169→pub fn encodeLiteralHeaderWithIncrementalIndexing(
170→    out: []u8,
171→    name: []const u8,
172→    value: []const u8,
173→) Error![]const u8 {
174→    assert(name.len > 0);
175→
176→    var cursor: usize = 0;
177→    if (cursor >= out.len) return error.BufferTooSmall;
178→
179→    out[cursor] = 0x40;
180→    cursor += 1;
181→    cursor = try encodeString(out, cursor, name);
182→    cursor = try encodeString(out, cursor, value);
183→    return out[0..cursor];
184→}
185→
186→pub fn encodeIndexedHeaderField(out: []u8, index: u32) Error![]const u8 {
187→    if (index == 0) return error.InvalidIndex;
188→    const cursor = try encodeInteger(out, 0, 7, 0x80, index);
189→    return out[0..cursor];
190→}
191→
192→fn decodeHeaderName(self: *Decoder, input: []const u8, cursor: *usize, prefix_bits: u8) Error![]const u8 {
193→    assert(@intFromPtr(self) != 0);
194→
195→    const name_index = try decodeInteger(input, cursor, prefix_bits);
196→    if (name_index == 0) {
197→        return try decodeString(self, input, cursor);
198→    }
199→
200→    const field = try resolveIndexedHeader(self, name_index);
201→    return field.name;
202→}
203→
204→fn resolveIndexedHeader(self: *const Decoder, index: u32) Error!HeaderField {
205→    assert(@intFromPtr(self) != 0);
206→
207→    if (index == 0) return error.InvalidIndex;
208→    if (index <= static_table.len) {
209→        const table_index: usize = @intCast(index - 1);
210→        return static_table[table_index];
211→    }
212→
213→    const dynamic_index_1_based = index - static_table.len;
214→    if (dynamic_index_1_based == 0) return error.InvalidIndex;
215→    if (dynamic_index_1_based > self.dynamic_entry_count) return error.UnsupportedDynamicTableIndex;
216→
217→    const slot: usize = @intCast(dynamic_index_1_based - 1);
218→    const entry = self.dynamic_entries[slot];
219→
220→    const name_start: usize = entry.name_offset;
221→    const name_len: usize = entry.name_len;
222→    const value_start: usize = entry.value_offset;
223→    const value_len: usize = entry.value_len;
224→
225→    return .{
226→        .name = self.dynamic_storage_buf[name_start .. name_start + name_len],
227→        .value = self.dynamic_storage_buf[value_start .. value_start + value_len],
228→    };
229→}
230→
231→fn applyDynamicTableSizeUpdate(self: *Decoder, dynamic_table_size_bytes: u32) Error!void {
232→    assert(@intFromPtr(self) != 0);
233→
234→    if (dynamic_table_size_bytes > self.max_dynamic_table_size_bytes) {
235→        return error.DynamicTableSizeTooLarge;
236→    }
237→
238→    self.dynamic_table_size_limit_bytes = dynamic_table_size_bytes;
239→    while (self.current_dynamic_table_size_bytes > self.dynamic_table_size_limit_bytes) {
240→        evictOldestDynamicEntry(self);
241→    }
242→}
243→
244→fn insertDynamicEntry(self: *Decoder, name: []const u8, value: []const u8) Error!void {
245→    assert(@intFromPtr(self) != 0);
246→
247→    const entry_size_bytes = try dynamicEntrySize(name.len, value.len);
248→    if (entry_size_bytes > self.dynamic_table_size_limit_bytes) {
249→        clearDynamicTable(self);
250→        return;
251→    }
252→
253→    while (self.current_dynamic_table_size_bytes + entry_size_bytes > self.dynamic_table_size_limit_bytes) {
254→        evictOldestDynamicEntry(self);
255→    }
256→
257→    while (self.dynamic_entry_count >= dynamic_entry_capacity) {
258→        evictOldestDynamicEntry(self);
259→    }
260→
261→    const required_storage_bytes = name.len + value.len;
262→    try ensureDynamicStorageSpace(self, required_storage_bytes);
263→
264→    const start: usize = self.dynamic_storage_len;
265→    const name_start = start;
266→    const value_start = start + name.len;
267→
268→    @memcpy(self.dynamic_storage_buf[name_start..][0..name.len], name);
269→    @memcpy(self.dynamic_storage_buf[value_start..][0..value.len], value);
270→
271→    var index: usize = self.dynamic_entry_count;
272→    while (index > 0) {
273→        self.dynamic_entries[index] = self.dynamic_entries[index - 1];
274→        index -= 1;
275→    }
276→
277→    self.dynamic_entries[0] = .{
278→        .name_offset = @intCast(name_start),
279→        .name_len = @intCast(name.len),
280→        .value_offset = @intCast(value_start),
281→        .value_len = @intCast(value.len),
282→        .size_bytes = entry_size_bytes,
283→    };
284→    self.dynamic_entry_count += 1;
285→    self.current_dynamic_table_size_bytes += entry_size_bytes;
286→    self.dynamic_storage_len = @intCast(start + required_storage_bytes);
287→}
288→
289→fn ensureDynamicStorageSpace(self: *Decoder, required_storage_bytes: usize) Error!void {
290→    assert(@intFromPtr(self) != 0);
291→
292→    const current_len: usize = self.dynamic_storage_len;
293→    if (current_len + required_storage_bytes <= dynamic_storage_capacity_bytes) return;
294→
295→    compactDynamicStorage(self);
296→
297→    const compacted_len: usize = self.dynamic_storage_len;
298→    if (compacted_len + required_storage_bytes > dynamic_storage_capacity_bytes) {
299→        return error.BufferTooSmall;
300→    }
301→}
302→
303→fn compactDynamicStorage(self: *Decoder) void {
304→    assert(@intFromPtr(self) != 0);
305→
306→    var compacted_buf: [dynamic_storage_capacity_bytes]u8 = undefined;
307→    var write_offset: usize = 0;
308→
309→    var reverse_index: usize = self.dynamic_entry_count;
310→    while (reverse_index > 0) {
311→        reverse_index -= 1;
312→        const entry = self.dynamic_entries[reverse_index];
313→
314→        const name_src_start: usize = entry.name_offset;
315→        const name_len: usize = entry.name_len;
316→        const value_src_start: usize = entry.value_offset;
317→        const value_len: usize = entry.value_len;
318→
319→        @memcpy(compacted_buf[write_offset..][0..name_len], self.dynamic_storage_buf[name_src_start..][0..name_len]);
320→        self.dynamic_entries[reverse_index].name_offset = @intCast(write_offset);
321→        self.dynamic_entries[reverse_index].name_len = @intCast(name_len);
322→        write_offset += name_len;
323→
324→        @memcpy(compacted_buf[write_offset..][0..value_len], self.dynamic_storage_buf[value_src_start..][0..value_len]);
325→        self.dynamic_entries[reverse_index].value_offset = @intCast(write_offset);
326→        self.dynamic_entries[reverse_index].value_len = @intCast(value_len);
327→        write_offset += value_len;
328→    }
329→
330→    @memcpy(self.dynamic_storage_buf[0..write_offset], compacted_buf[0..write_offset]);
331→    self.dynamic_storage_len = @intCast(write_offset);
332→}
333→
334→fn evictOldestDynamicEntry(self: *Decoder) void {
335→    assert(@intFromPtr(self) != 0);
336→
337→    if (self.dynamic_entry_count == 0) {
338→        self.current_dynamic_table_size_bytes = 0;
339→        self.dynamic_storage_len = 0;
340→        return;
341→    }
342→
343→    const oldest_index: usize = self.dynamic_entry_count - 1;
344→    const oldest = self.dynamic_entries[oldest_index];
345→
346→    if (oldest.size_bytes <= self.current_dynamic_table_size_bytes) {
347→        self.current_dynamic_table_size_bytes -= oldest.size_bytes;
348→    } else {
349→        self.current_dynamic_table_size_bytes = 0;
350→    }
351→
352→    self.dynamic_entry_count -= 1;
353→    if (self.dynamic_entry_count == 0) {
354→        self.current_dynamic_table_size_bytes = 0;
355→        self.dynamic_storage_len = 0;
356→    }
357→}
358→
359→fn clearDynamicTable(self: *Decoder) void {
360→    assert(@intFromPtr(self) != 0);
361→
362→    self.current_dynamic_table_size_bytes = 0;
363→    self.dynamic_entry_count = 0;
364→    self.dynamic_storage_len = 0;
365→}
366→
367→fn dynamicEntrySize(name_len: usize, value_len: usize) Error!u32 {
368→    const name_u32: u32 = @intCast(name_len);
369→    const value_u32: u32 = @intCast(value_len);
370→
371→    const payload = std.math.add(u32, name_u32, value_u32) catch return error.IntegerOverflow;
372→    return std.math.add(u32, payload, dynamic_entry_overhead_size_bytes) catch return error.IntegerOverflow;
373→}
374→
375→fn decodeInteger(input: []const u8, cursor: *usize, prefix_bits: u8) Error!u32 {
376→    assert(prefix_bits > 0);
377→    assert(prefix_bits < 8);
378→    assert(cursor.* < input.len);
379→
380→    const prefix_mask: u8 = (@as(u8, 1) << @intCast(prefix_bits)) - 1;
381→    const first = input[cursor.*];
382→    var value: u32 = first & prefix_mask;
383→    cursor.* += 1;
384→
385→    if (value < prefix_mask) return value;
386→
387→    var shift: u6 = 0;
388→    while (true) {
389→        if (cursor.* >= input.len) return error.NeedMoreData;
390→        if (shift >= 28) return error.IntegerOverflow;
391→
392→        const b = input[cursor.*];
393→        cursor.* += 1;
394→        value += (@as(u32, b & 0x7f) << @as(u5, @intCast(shift)));
395→        if ((b & 0x80) == 0) return value;
396→        shift += 7;
397→    }
398→}
399→
400→fn decodeString(self: *Decoder, input: []const u8, cursor: *usize) Error![]const u8 {
401→    assert(@intFromPtr(self) != 0);
402→
403→    if (cursor.* >= input.len) return error.NeedMoreData;
404→
405→    const huffman_encoded = (input[cursor.*] & 0x80) != 0;
406→
407→    const len_u32 = try decodeInteger(input, cursor, 7);
408→    const len: usize = @intCast(len_u32);
409→    if (cursor.* + len > input.len) return error.InvalidStringLength;
410→
411→    const str = input[cursor.* .. cursor.* + len];
412→    cursor.* += len;
413→
414→    if (!huffman_encoded) return str;
415→
416→    const scratch_start: usize = self.huffman_scratch_len;
417→    const decoded = huffman.decode(str, self.huffman_scratch_buf[scratch_start..]) catch |err| switch (err) {
418→        error.InvalidHuffman => return error.InvalidHuffman,
419→        error.BufferTooSmall => return error.BufferTooSmall,
420→    };
421→
422→    self.huffman_scratch_len = @intCast(scratch_start + decoded.len);
423→    return self.huffman_scratch_buf[scratch_start .. scratch_start + decoded.len];
424→}
425→
426→fn encodeInteger(out: []u8, cursor_start: usize, prefix_bits: u8, first_prefix: u8, value: u32) Error!usize {
427→    assert(prefix_bits > 0);
428→    assert(prefix_bits < 8);
429→    assert(cursor_start < out.len);
430→
431→    const prefix_max: u32 = (@as(u32, 1) << @intCast(prefix_bits)) - 1;
432→    var cursor = cursor_start;
433→
434→    if (value < prefix_max) {
435→        out[cursor] = first_prefix | @as(u8, @intCast(value));
436→        return cursor + 1;
437→    }
438→
439→    out[cursor] = first_prefix | @as(u8, @intCast(prefix_max));
440→    cursor += 1;
441→
442→    var remaining = value - prefix_max;
443→    while (remaining >= 128) {
444→        if (cursor >= out.len) return error.BufferTooSmall;
445→        out[cursor] = @as(u8, @intCast((remaining & 0x7f) | 0x80));
446→        remaining >>= 7;
447→        cursor += 1;
448→    }
449→
450→    if (cursor >= out.len) return error.BufferTooSmall;
451→    out[cursor] = @as(u8, @intCast(remaining));
452→    return cursor + 1;
453→}
454→
455→fn encodeString(out: []u8, cursor_start: usize, data: []const u8) Error!usize {
456→    var cursor = try encodeInteger(out, cursor_start, 7, 0x00, @intCast(data.len));
457→    if (cursor + data.len > out.len) return error.BufferTooSmall;
458→    @memcpy(out[cursor..][0..data.len], data);
459→    cursor += data.len;
460→    return cursor;
461→}
462→
463→const static_table = [_]HeaderField{
464→    .{ .name = ":authority", .value = "" },
465→    .{ .name = ":method", .value = "GET" },
466→    .{ .name = ":method", .value = "POST" },
467→    .{ .name = ":path", .value = "/" },
468→    .{ .name = ":path", .value = "/index.html" },
