  1→//! HTTP/2 Server Connection State
  2→//!
  3→//! Bounded per-connection HTTP/2 state for the future stream-aware server
  4→//! transport.
  5→//! TigerStyle: Explicit state, fixed-capacity tables, no socket ownership.
  6→
  7→const std = @import("std");
  8→const assert = std.debug.assert;
  9→
 10→const config = @import("serval-core").config;
 11→const h2 = @import("serval-h2");
 12→
 13→pub const Error = error{
 14→    DuplicatePreface,
 15→    LocalSettingsAlreadySent,
 16→    UnexpectedSettingsAck,
 17→} || h2.SettingsError || h2.StreamError || h2.flow_control.Error;
 18→
 19→pub const ConnectionState = struct {
 20→    preface_received: bool = false,
 21→    peer_settings_received: bool = false,
 22→    local_settings_sent: bool = false,
 23→    peer_settings: h2.Settings = .{},
 24→    local_settings: h2.Settings = defaultLocalSettings(),
 25→    peer_settings_ack_pending: bool = false,
 26→    local_settings_ack_pending: bool = false,
 27→    goaway_received: bool = false,
 28→    goaway_sent: bool = false,
 29→    peer_goaway_last_stream_id: u32 = 0,
 30→    local_goaway_last_stream_id: u32 = 0,
 31→    streams: h2.StreamTable = h2.StreamTable.init(.server),
 32→    flow: h2.ConnectionFlowControl,
 33→
 34→    pub fn init() Error!ConnectionState {
 35→        const flow = try h2.ConnectionFlowControl.init(config.H2_CONNECTION_WINDOW_SIZE_BYTES);
 36→        return .{ .flow = flow };
 37→    }
 38→
 39→    pub fn markPrefaceReceived(self: *ConnectionState) Error!void {
 40→        assert(@intFromPtr(self) != 0);
 41→        assert(self.flow.recv_window.available_bytes <= config.H2_MAX_WINDOW_SIZE_BYTES);
 42→
 43→        if (self.preface_received) return error.DuplicatePreface;
 44→        self.preface_received = true;
 45→    }
 46→
 47→    pub fn markLocalSettingsSent(self: *ConnectionState) Error!void {
 48→        assert(@intFromPtr(self) != 0);
 49→        assert(self.local_settings.max_frame_size_bytes <= config.H2_MAX_FRAME_SIZE_BYTES);
 50→
 51→        if (self.local_settings_sent) return error.LocalSettingsAlreadySent;
 52→        self.local_settings_sent = true;
 53→        self.local_settings_ack_pending = true;
 54→    }
 55→
 56→    pub fn receivePeerSettings(
 57→        self: *ConnectionState,
 58→        header: h2.FrameHeader,
 59→        payload: []const u8,
 60→    ) Error!void {
 61→        assert(@intFromPtr(self) != 0);
 62→        assert(header.frame_type == .settings);
 63→
 64→        var parsed_buf: [config.H2_MAX_SETTINGS_PER_FRAME]h2.Setting = undefined;
 65→        const parsed = try h2.parseSettingsFrame(header, payload, &parsed_buf);
 66→
 67→        if ((header.flags & h2.flags_ack) != 0) {
 68→            if (!self.local_settings_ack_pending) return error.UnexpectedSettingsAck;
 69→            self.local_settings_ack_pending = false;
 70→            return;
 71→        }
 72→
 73→        const old_initial_window_size_bytes = self.peer_settings.initial_window_size_bytes;
 74→        try h2.applySettings(&self.peer_settings, parsed);
 75→
